mapper.insert:
INSERT INTO 
	CMS_SURVEY_ANSWER_USER
(
	homepage_id, survey_idx, add_user_id, add_date, add_user_div, add_user_ip, add_user_name, member_key
) VALUES
(
	#{homepage_id}, #{survey_idx}, #{add_user_id}, SYSDATE, ' ', #{add_user_ip}, #{add_user_name}, #{member_key}
)

INSERT INTO
	CMS_SURVEY_ANSWER_DETAIL
(
	homepage_id, survey_idx, quest_idx, answer_idx, add_user_id, add_date,
	choice_answer, short_answer
) VALUES
(
	#{homepage_id}, #{survey_idx}, #{answer.quest_idx}, #{answer.answer_idx}, #{add_user_id}, SYSDATE,
	#{answer.choice_answer}, #{answer.short_answer}
)

INSERT INTO
	CMS_SURVEY_ANSWER_MATRIX
(
	homepage_id, survey_idx, quest_idx, answer_idx, add_user_id, matrix_idx,
	matrix_answer
) VALUES
(
	#{homepage_id}, #{survey_idx}, #{answer.quest_idx}, #{answer.answer_idx}, #{add_user_id}, #{answer.matrix_idx},
	#{answer.choice_answer}
)

mapper.select:
SELECT
	COUNT(*)
FROM
	CMS_SURVEY_ANSWER_USER
WHERE
	survey_idx = #{survey_idx}
AND	add_user_id = #{add_user_id}
AND homepage_id = #{homepage_id}
